import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    next_node = None
    min_product = np.inf

    for node in unvisited_nodes:
        if node not in truck_nodes:
            product = distance_matrix[current_node][node] * distance_matrix[node][depot_node]
            if product < min_product:
                min_product = product
                next_node = node

    return next_node
